OPEN_SMALL = self_hosted_client("qwen-2.5-7b")     # inside boundary
OPEN_LARGE = self_hosted_client("llama-3.1-70b")   # inside boundary
FRONTIER   = hosted_client("claude-sonnet-4-6")    # crosses boundary

THRESHOLD  = 0.7

function route(request):
    # 1. Sensitivity classification BEFORE any model call.
    if pii_classifier.is_sensitive(request):
        out = OPEN_LARGE.generate(request)
        if out.confidence < THRESHOLD:
            # Sensitive + uncertain: refuse / degrade.
            # NEVER escalate sensitive traffic across the boundary.
            return degrade(request, reason="sensitive_uncertain")
        return out

    # 2. Insensitive easy: smallest local model.
    out = OPEN_SMALL.generate(request)
    if out.confidence >= THRESHOLD:
        return out

    # 3. Insensitive hard: escalate to frontier.
    return FRONTIER.generate(request)

