# --- Sectioning ---------------------------------------------------
function sectioned_run(task):
    subtasks = split(task)              # independent pieces
    parts    = parallel_map(
        lambda sub: llm.generate(sub),
        subtasks,
    )
    return concat(parts)

# --- Voting -------------------------------------------------------
function voted_run(task, n=5):
    samples = parallel_map(
        lambda _: llm.generate(task, temperature=0.7),
        range(n),
    )
    return aggregate(samples)           # majority vote OR judge model

